module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0] dout_parallel,
    output dout_valid
);
    reg [2:0] cnt;

    always @(posedge clk) begin
        if (!rst_n) begin
            cnt <= 3'd0;
            dout_parallel <= 8'd0;
        end
        else if (din_valid) begin
            dout_parallel[7-cnt] <= din_serial;
            if (cnt == 3'd7) cnt <= 3'd0;
            else cnt <= cnt + 1;
        end
    end

    always @(posedge clk) begin
        if (!rst_n) dout_valid <= 1'b0;
        else if (cnt == 3'd7) dout_valid <= 1'b1;
        else dout_valid <= 1'b0;
    end
endmodule
